mapper.select:
SELECT tne.id, tne.node_name AS nodeName, tne.node_key AS nodeKey, ter.remark AS procName, tne.complete_time AS completeTime, tne.process_duration AS processDuration, u.nick_name AS claimUserName, ter.proc_inst_id AS procInstId FROM task_node_execution tne LEFT JOIN task_execution_record ter ON ter.id = tne.exec_record_id LEFT JOIN sys_user u ON u.user_id = tne.claim_user_id WHERE tne.status = 'completed'
AND tne.claim_user_id = #{userId}
AND tne.assigned_team_id = #{teamId}
ORDER BY tne.complete_time DESC LIMIT #{limit}

