mapper.select:
SELECT tne.id, tne.node_key AS nodeKey, tne.node_name AS nodeName, tne.status, tne.start_time AS startTime, tne.complete_time AS completeTime, tne.plan_start_date AS planStartDate, tne.plan_end_date AS planEndDate, COALESCE( NULLIF(tne.plan_end_date, ''), DATE_FORMAT(tne.start_time, '%Y-%m-%d') ) AS displayDate, tne.timeout_flag AS timeoutFlag, tne.process_duration AS processDuration, pt.team_name AS teamName, ter.proc_inst_id AS procInstId, hv.TEXT_ AS taskName, u.nick_name AS claimUserName FROM task_node_execution tne LEFT JOIN task_execution_record ter ON ter.id = tne.exec_record_id LEFT JOIN production_team pt ON pt.id = tne.assigned_team_id LEFT JOIN ACT_HI_VARINST hv ON hv.PROC_INST_ID_ = ter.proc_inst_id AND hv.NAME_ = 'taskName' LEFT JOIN sys_user u ON u.user_id = tne.claim_user_id WHERE tne.status != 'cancelled' AND COALESCE( NULLIF(tne.plan_end_date, ''), DATE_FORMAT(tne.start_time, '%Y-%m-%d') ) >= #{monthStart} AND COALESCE( NULLIF(tne.plan_end_date, ''), DATE_FORMAT(tne.start_time, '%Y-%m-%d') ) <= #{monthEnd}
AND (
tne.assigned_team_id IN #{tid}
OR (tne.assigned_team_id IN #{tid} AND (tne.claim_user_id = #{userId} OR tne.assigned_user_id = #{userId} OR tne.claim_user_id IS NULL))
(tne.claim_user_id = #{userId} OR tne.assigned_user_id = #{userId} OR tne.claim_user_id IS NULL)
)
ORDER BY displayDate ASC, tne.status ASC
